{"command": "WORKDIR="/tmp/sv-8c0ac7f16a60414d9f25295041374efd/symbols"
LIB="$WORKDIR/libmonosgen-2.0.so"

# Get all defined dynamic symbols sorted by address, we'll use this to find the function for each PC
# Format: address type name
nm -D --defined-only "$LIB" 2>/dev/null | grep -E '^[0-9a-f]+ [TtWw]' | sort > "$WORKDIR/syms_sorted.txt"
wc -l "$WORKDIR/syms_sorted.txt"

# Now for each address, find the nearest symbol (the one with the largest address <= target)
for addr in 0x222098 0x2241ac 0x1abc80 0x16de04 0x2f4b20 0x2f4c84 0x2c1a40; do
  decimal=$(printf "%d" "$addr")
  # Find the last symbol with address <= target
  result=$(awk -v target="$decimal" '
    BEGIN { best_addr=0; best_name="??"; }
    {
      addr = strtonum("0x" $1)
      if (addr <= target) { best_addr = addr; best_name = $3; }
    }
    END { printf "0x%x %s+0x%x\n", best_addr, best_name, target - best_addr; }
  ' "$WORKDIR/syms_sorted.txt")
  printf "  %-12s -> %s\n" "$addr" "$result"
done", "description": "Symbolicate addresses using dynamic symbols"}

{"command": "WORKDIR="/tmp/sv-8c0ac7f16a60414d9f25295041374efd/symbols"
DBGFILE="$WORKDIR/debug/libmonosgen-2.0.so.dbg"

# Try with inlining info for the SGen worker addresses
echo "=== SGen worker addresses with inlining ==="
for addr in 0x2f4b20 0x2f4c84; do
  echo "--- $addr ---"
  addr2line -C -f -i -e "$DBGFILE" "$addr" 2>&1
done

# Also try nm to find the symbol at these addresses
echo ""
echo "=== nm lookup for SGen addresses ==="
nm --defined-only "$DBGFILE" 2>/dev/null | sort | awk -v a1="3141408" -v a2="3141764" '
  {
    addr = strtonum("0x" $1)
    if (addr <= 3141408) { b1_addr=$1; b1_name=$3 }
    if (addr <= 3141764) { b2_addr=$1; b2_name=$3 }
  }
  END {
    printf "0x2f4b20 -> 0x%s %s (+0x%x)\n", b1_addr, b1_name, 3141408 - strtonum("0x" b1_addr)
    printf "0x2f4c84 -> 0x%s %s (+0x%x)\n", b2_addr, b2_name, 3141764 - strtonum("0x" b2_addr)
  }
'", "description": "Resolve SGen worker symbols with nm"}

{"command": "WORKDIR="/tmp/sv-8c0ac7f16a60414d9f25295041374efd/symbols"
DBGFILE="$WORKDIR/debug/libmonosgen-2.0.so.dbg"

# Get sorted function symbols and find the function containing each SGen address
nm --defined-only "$DBGFILE" 2>/dev/null | grep -E ' [Tt] ' | sort > "$WORKDIR/all_syms.txt"
wc -l "$WORKDIR/all_syms.txt"

# Find the function for 0x2f4b20 and 0x2f4c84
for target_hex in 2f4b20 2f4c84 2c1a40; do
  target=$((16#$target_hex))
  result=$(awk -v target="$target" '
    BEGIN { best_addr=0; best_name="??"; }
    {
      addr = strtonum("0x" $1)
      if (addr <= target) { best_addr = addr; best_name = $3; }
    }
    END { printf "0x%x %s+0x%x\n", best_addr, best_name, target - best_addr; }
  ' "$WORKDIR/all_syms.txt")
  printf "  0x%-8s -> %s\n" "$target_hex" "$result"
done", "description": "Find function symbols for SGen addresses"}

{"command": "WORKDIR="/tmp/sv-8c0ac7f16a60414d9f25295041374efd/symbols"
DBGFILE="$WORKDIR/debug/libmonosgen-2.0.so.dbg"

# Get more symbols in the range
nm --defined-only "$DBGFILE" 2>/dev/null | sort | awk '
